import { Client as SendgridClient } from '@sendgrid/mail';
import stripe from 'stripe';

const sendgridAPIKey = process.env.SENDGRID_API_KEY;
const stripeSecretKey = process.env.STRIPE_SECRET_KEY;

if (!sendgridAPIKey || !stripeSecretKey) {
  console.error('Missing environment variables.');
  deno_exit(1);
}

const sendgridClient = new SendgridClient(sendgridAPIKey);
const stripeClient = stripe(stripeSecretKey);

export async function handleRequest({ request, env }) {
  const body = await request.text();
  const data = JSON.parse(body);

  if (!data.email || !data.amount) {
    console.error('Missing email or amount.');
    return new Response('Invalid Request', { status: 400 });
  }

  try {
    await stripeClient.charges.create({
      amount: data.amount,
      currency: 'usd',
      source: 'tok_visa', // replace with your actual payment source
      recipient_email: data.email,
    });

    const message = {
      to: data.email,
      from: 'sender@example.com',
      subject: 'Your Payment Receipt',
      text: 'Thank you for your purchase!',
    };

    await sendgridClient.send(message);

    return new Response('Payment and email sent successfully.', { status: 200 });
  } catch (error) {
    console.error(error);
    return new Response('Error processing payment.', { status: 500 });
  }
}